async getBatchStats(batchId: string) {
  const batch = await this.examBatchRepository.findById(batchId);
  if (!batch) throw new Error('Batch not found');

  const results: any[] = batch.studentResults || [];
  const total = results.length;
  const passed = results.filter(r => r.result === 'pass').length;
  const failed = results.filter(r => r.result === 'fail').length;
  const absent = results.filter(r => r.result === 'absent').length;
  const noResult = results.filter(r => r.result === 'no_result').length;

  return {
    total,
    passed,
    failed,
    absent,
    noResult,
    failedBySection: {
      theory: results.filter(r => r.theory_result === 'fail').length,
      simulation: results.filter(r => r.simulation_result === 'fail').length,
      parking: results.filter(r => r.parking_result === 'fail').length,
      road: results.filter(r => r.road_result === 'fail').length,
    }
  };
}
```

