import { Request, Response } from 'express';
import { ExamBatchService } from '@/application/services/exam_batch.service';
import { ExamBatchRepository } from '@/infrastructure/database/repositories/exam_batch.repository';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import multer from 'multer';

const examBatchRepository = new ExamBatchRepository();
const examBatchService = new ExamBatchService(examBatchRepository);
const upload = multer({ storage: multer.memoryStorage() });

export const importExamResults = catchAsync(async (req: Request, res: Response) => {
  const file = (req as any).file;
  const { batchId } = req.body;

  if (!file) return res.statusError('No file uploaded', 400);
  if (!batchId) return res.statusError('batchId is required', 400);

  const XLSX = require('xlsx');
  const workbook = XLSX.read(file.buffer, { type: 'buffer' });
  const sheet = workbook.Sheets[workbook.SheetNames[0]];
  const rows: any[] = XLSX.utils.sheet_to_json(sheet);

  if (rows.length === 0) return res.statusError('File is empty', 400);

  const batch = await examBatchService.getBatchById(batchId);
  if (!batch) return res.statusError('Exam batch not found', 404);

  const existingMap = new Map(
    (batch.studentResults || []).map((r: any) => [r.student_id, r])
  );

  for (const row of rows) {
    existingMap.set(String(row.student_id), {
      student_id: String(row.student_id),
      name: String(row.name || row.student_id),
      result: ['pass', 'fail', 'absent', 'no_result'].includes(row.result) ? row.result : 'no_result',
      theory_result: ['pass', 'fail', 'absent'].includes(row.theory_result) ? row.theory_result : undefined,
      simulation_result: ['pass', 'fail', 'absent'].includes(row.simulation_result) ? row.simulation_result : undefined,
      parking_result: ['pass', 'fail', 'absent'].includes(row.parking_result) ? row.parking_result : undefined,
      road_result: ['pass', 'fail', 'absent'].includes(row.road_result) ? row.road_result : undefined,
      note: String(row.note || ''),
    });
  }

  await examBatchService.updateBatch(batchId, { 
    studentResults: Array.from(existingMap.values()) 
  });

  res.statusSuccess({ imported: rows.length }, 'Import thành công');
});

export const getBatchStats = catchAsync(async (req: Request, res: Response) => {
  const idStr = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  const stats = await examBatchService.getBatchStats(idStr);
  res.statusSuccess(stats, 'Batch stats retrieved');
});
```

