import mongoose, { Schema, Document } from 'mongoose';

export interface IExamBatch extends Document {
  name: string;
  vehicleType: string;
  region: string;
  examDate: Date;
  officialDate?: Date;
  venue: string;
  stadium_id?: string;
  status: 'upcoming' | 'confirmed' | 'completed' | 'cancelled';
  studentResults: any[];
  created_at: Date;
  updated_at: Date;
}

const ExamBatchSchema = new Schema<IExamBatch>({
  name: { type: String, required: true, trim: true },
  vehicleType: { type: String, required: true, trim: true },
  region: { type: String, required: true, trim: true },
  examDate: { type: Date, required: true },
  officialDate: { type: Date },
  venue: { type: String, required: true, trim: true },
  stadium_id: { type: String, trim: true },
  status: { 
    type: String, 
    enum: ['upcoming', 'confirmed', 'completed', 'cancelled'], 
    default: 'upcoming' 
  },
  studentResults: [{ type: Schema.Types.Mixed }],
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

ExamBatchSchema.index({ name: 1 });
ExamBatchSchema.index({ status: 1 });
ExamBatchSchema.index({ examDate: 1 });

const ExamBatchModel = mongoose.models.ExamBatch || mongoose.model<IExamBatch>('ExamBatch', ExamBatchSchema);

export default ExamBatchModel;

import { IExamBatchRepository } from '@/domain/repositories/exam_batch.repository.interface';
import { ExamBatch } from '@/domain/entities/exam_batch.entity';
import { PaginationOptions, PaginatedResult } from '@/domain/types/pagination.types';
import { ExcelHelper } from '@/infrastructure/utils/excel.helper';
import { Response } from 'express';
// Removed: obsolete model import

export class ExamBatchService {
  private excelHelper: ExcelHelper;

  constructor(private examBatchRepository: IExamBatchRepository) {
    this.excelHelper = new ExcelHelper();
  }

  async createBatch(data: Omit<ExamBatch, 'id' | 'createdAt' | 'updatedAt'>): Promise<ExamBatch> {
    return await this.examBatchRepository.create(data);
  }

  async getAllBatches(options?: PaginationOptions): Promise<PaginatedResult<ExamBatch>> {
    return await this.examBatchRepository.findAll(options);
  }

  async getBatchById(id: string): Promise<ExamBatch | null> {
    return await this.examBatchRepository.findById(id);
  }

  async updateBatch(id: string, data: Partial<Omit<ExamBatch, 'id'>>): Promise<ExamBatch | null> {
    return await this.examBatchRepository.update(id, data);
  }

  async deleteBatch(id: string): Promise<boolean> {
    return await this.examBatchRepository.delete(id);
  }

  async exportBatchesToExcel(res: Response, filters: any = {}): Promise<void> {
    // Thay vì gọi ExamBatchModel trực tiếp, ta dùng repository
    const batches = await this.examBatchRepository.getAllForExport(filters);

    const { workbook, worksheet } = this.excelHelper.createWorkbook('Danh sách đợt thi sát hạch');

    this.excelHelper.applyHeaderStyle(worksheet, [
      { header: 'Tên đợt thi', key: 'name', width: 30 },
      { header: 'Loại xe', key: 'vehicleType', width: 15 },
      { header: 'Khu vực', key: 'region', width: 20 },
      { header: 'Địa điểm', key: 'venue', width: 25 },
      { header: 'Ngày dự kiến', key: 'examDate', width: 18 },
      { header: 'Ngày chính thức', key: 'officialDate', width: 18 },
      { header: 'Trạng thái', key: 'status', width: 15 },
      { header: 'Tổng thí sinh', key: 'total', width: 15 },
      { header: 'Số đậu', key: 'passed', width: 12 },
      { header: 'Số rớt', key: 'failed', width: 12 },
    ]);

    const statusLabel: Record<string, string> = {
      upcoming: 'Sắp diễn ra',
      confirmed: 'Đã xác nhận',
      completed: 'Đã hoàn thành',
      cancelled: 'Đã hủy',
    };

    batches.forEach((batch: any) => {
      const results: any[] = batch.studentResults || [];
      const passedCount = results.filter((r: any) => r.result === 'pass').length;
      const failedCount = results.filter((r: any) => r.result === 'fail').length;

      worksheet.addRow({
        name: batch.name || '',
        vehicleType: batch.vehicleType || '',
        region: batch.region || '',
        venue: batch.venue || '',
        examDate: batch.examDate ? new Date(batch.examDate).toLocaleDateString('vi-VN') : '',
        officialDate: batch.officialDate ? new Date(batch.officialDate).toLocaleDateString('vi-VN') : '',
        status: statusLabel[batch.status] || batch.status || '',
        total: results.length,
        passed: passedCount,
        failed: failedCount,
      });
    });

    this.excelHelper.applyRowStyle(worksheet);
    await this.excelHelper.sendWorkbook(res, workbook, 'danh_sach_dot_thi_sat_hach');
  }
}

