import { createExamBatchSchema, updateExamBatchSchema } from '@/interface/dtos/exam_batch.dto';

const router = express.Router();

router.post('/', validate(createExamBatchSchema), examBatchController.createBatch);
router.get('/export', examBatchController.exportBatches);
router.get('/', paginationMiddleware, examBatchController.getAllBatches);
router.get('/:id', examBatchController.getBatchById);
router.patch('/:id', validate(updateExamBatchSchema), examBatchController.updateBatch);
router.delete('/:id', examBatchController.deleteBatch);

export default router;

